/**
 * Tech Tree: DAG of technology nodes gating progression.
 *
 * Five branches: Mining, Logistics, Anomaly Research, Energy & Thermal, Propulsion & Navigation
 * 80 nodes implemented across all branches.
 *
 * State is a bitmask of unlocked node indices + active research tracking.
 */

// ── Branch IDs ──────────────────────────────────────────────────────────────

export const TECH_BRANCHES = {
  MINING: 0,
  LOGISTICS: 1,
  ANOMALY: 2,
  ENERGY: 3,
  PROPULSION: 4,
} as const;

// ── Unlock effect types ──────────────────────────────────────────────────────

/** String identifiers used in building unlock effects — must match values in TECH_NODES */
export type BuildingEffectId =
  | 'refinery'
  | 'advanced_refinery'
  | 'robot_factory'
  | 'solar_panel'
  | 'radiator'
  | 'solar_furnace'
  | 'rtg_module'
  | 'fission_reactor'
  | 'fusion_reactor'
  | 'energy_relay';

export type UnlockEffect =
  | { kind: 'tool_tier'; tier: number }
  | { kind: 'robot_type'; robotType: number }
  | { kind: 'building'; buildingType: BuildingEffectId }
  | { kind: 'efficiency'; system: string; multiplier: number }
  | { kind: 'narrative_trigger'; eventId: string };

// ── Tech node definition ─────────────────────────────────────────────────────

export interface TechNode {
  id: string;
  index: number; // position in bitmask (0–62)
  name: string;
  description: string;
  branch: number;
  prerequisites: string[]; // node ids that must be unlocked first
  researchPoints: number; // points needed to unlock
  resourceCost: Partial<Record<string, number>>; // resource name -> quantity (raw or refined)
  unlockEffects: UnlockEffect[];
  hidden?: boolean; // starts hidden until a prerequisite condition is met
}

