// Build lookup map
export const TECH_NODE_BY_ID: Map<string, TechNode> = new Map(TECH_NODES.map((n) => [n.id, n]));

// ── Runtime state ────────────────────────────────────────────────────────────

export interface ActiveResearch {
  nodeId: string;
  pointsAccumulated: number;
  pointsRequired: number;
  startedAt: number; // sim time in seconds
}

export interface TechState {
  /** Bitmask of unlocked node indices (up to 63 nodes) */
  unlockedMask: bigint;
  /** Bitmask of visible (non-hidden) node indices */
  visibleMask: bigint;
  /** Currently active research project, or null */
  activeResearch: ActiveResearch | null;
  /** Accumulated research points per second (from researcher robots) */
  researchRate: number;
  /** Total research points generated (lifetime) */
  totalPointsGenerated: number;
}

export function createTechState(): TechState {
  // All non-hidden nodes start visible
  let visibleMask = 0n;
  for (const node of TECH_NODES) {
    if (!node.hidden) {
      visibleMask |= 1n << BigInt(node.index);
    }
  }
  // Unlock researcher_bots from the start — researchers are the only way to
  // generate RP, so gating them behind RP creates a chicken-and-egg problem.
  const researcherNode = TECH_NODE_BY_ID.get('researcher_bots');
  const initialUnlocked = researcherNode ? 1n << BigInt(researcherNode.index) : 0n;

  return {
    unlockedMask: initialUnlocked,
    visibleMask,
    activeResearch: null,
    researchRate: 0,
    totalPointsGenerated: 0,
  };
}

// ── State queries ─────────────────────────────────────────────────────────────

export function isTechUnlocked(state: TechState, nodeId: string): boolean {
  const node = TECH_NODE_BY_ID.get(nodeId);
  if (!node) return false;
  return (state.unlockedMask & (1n << BigInt(node.index))) !== 0n;
}

export function isTechVisible(state: TechState, nodeId: string): boolean {
  const node = TECH_NODE_BY_ID.get(nodeId);
  if (!node) return false;
  return (state.visibleMask & (1n << BigInt(node.index))) !== 0n;
}

export function getAvailableNodes(state: TechState): TechNode[] {
  return TECH_NODES.filter((node) => {
    if (!isTechVisible(state, node.id)) return false;
    if (isTechUnlocked(state, node.id)) return false;
    return node.prerequisites.every((prereqId) => isTechUnlocked(state, prereqId));
  });
}

export function getUnlockedEffects(state: TechState, kind: UnlockEffect['kind']): UnlockEffect[] {
  const effects: UnlockEffect[] = [];
  for (const node of TECH_NODES) {
    if (!isTechUnlocked(state, node.id)) continue;
    for (const effect of node.unlockEffects) {
      if (effect.kind === kind) effects.push(effect);
    }
  }
  return effects;
}

/** Aggregate efficiency multiplier for a given system across all unlocked nodes */
export function getEfficiencyMultiplier(state: TechState, system: string): number {
  let multiplier = 1.0;
  for (const effect of getUnlockedEffects(state, 'efficiency')) {
    const e = effect as { kind: 'efficiency'; system: string; multiplier: number };
    if (e.system === system) multiplier *= e.multiplier;
  }
  return multiplier;
}

/** Highest unlocked tool tier (0 = none, 1 = Drill, 2 = Laser Cutter, 3 = Plasma Torch) */
export function getMaxToolTier(state: TechState): number {
  let max = 1; // tier 1 (Drill) always available
  for (const effect of getUnlockedEffects(state, 'tool_tier')) {
    const e = effect as { kind: 'tool_tier'; tier: number };
    if (e.tier > max) max = e.tier;
  }
  return max;
}

/** Returns the bitmask for a given tech node ID (for use outside the worker thread) */
export function techBitmask(nodeId: string): bigint {
  const node = TECH_NODE_BY_ID.get(nodeId);
  if (!node) throw new Error(`Unknown tech node: ${nodeId}`);
  return 1n << BigInt(node.index);
}

/** Check if a robot type is unlocked */
export function isRobotTypeUnlocked(state: TechState, robotType: number): boolean {
  // Types 0-2 (Scout, Miner, Hauler) are always available
  if (robotType <= 2) return true;
  for (const effect of getUnlockedEffects(state, 'robot_type')) {
    const e = effect as { kind: 'robot_type'; robotType: number };
    if (e.robotType === robotType) return true;
  }
  return false;
}

/** Check if a building type is unlocked */
export function isBuildingUnlocked(state: TechState, buildingType: BuildingEffectId): boolean {
  for (const effect of getUnlockedEffects(state, 'building')) {
    const e = effect as { kind: 'building'; buildingType: BuildingEffectId };
    if (e.buildingType === buildingType) return true;
  }
  return false;
}

// ── Research actions ──────────────────────────────────────────────────────────

export interface ResearchResult {
  ok: boolean;
  error?: string;
}

/** Start researching a node. Returns error string if prerequisites not met. */
export function startResearch(
  state: TechState,
  nodeId: string,
  storage: Record<string, number>,
): ResearchResult {
  const node = TECH_NODE_BY_ID.get(nodeId);
  if (!node) return { ok: false, error: 'Unknown tech node' };
  if (!isTechVisible(state, nodeId)) return { ok: false, error: 'Node not yet visible' };
  if (isTechUnlocked(state, nodeId)) return { ok: false, error: 'Already unlocked' };
  if (node.prerequisites.some((p) => !isTechUnlocked(state, p))) {
    return { ok: false, error: 'Prerequisites not met' };
  }

  // Check resources
  for (const res of Object.keys(node.resourceCost)) {
    const qty = node.resourceCost[res];
    if (qty !== undefined && (storage[res] ?? 0) < qty) {
      return {
        ok: false,
        error: `Insufficient ${res}: need ${qty}, have ${Math.floor(storage[res] ?? 0)}`,
      };
    }
  }

  // Deduct resources
  for (const res of Object.keys(node.resourceCost)) {
    const qty = node.resourceCost[res];
    if (qty !== undefined) storage[res] = (storage[res] ?? 0) - qty;
  }

  state.activeResearch = {
    nodeId,
    pointsAccumulated: 0,
    pointsRequired: node.researchPoints,
    startedAt: 0,
  };

  return { ok: true };
}

/** Probability that a completed research direction is a dead end and must be restarted. */
export const RESEARCH_DEAD_END_CHANCE = 0.15;

export interface ResearchTickResult {
  /** Node ID if a tech was just completed, else null. */
  completed: string | null;
  /** True if a dead end was hit this tick (research resets). */
  deadEnd: boolean;
}

/**
 * Tick the research system.
 * @param rng - Random number generator (0–1). Defaults to Math.random.
 * @returns Result with completed nodeId and dead-end flag.
 */
export function tickResearch(
  state: TechState,
  dt: number,
  rng: () => number = Math.random,
): ResearchTickResult {
  if (!state.activeResearch) return { completed: null, deadEnd: false };

  const pointsGained = state.researchRate * dt;
  state.activeResearch.pointsAccumulated += pointsGained;
  state.totalPointsGenerated += pointsGained;

  if (state.activeResearch.pointsAccumulated >= state.activeResearch.pointsRequired) {
    // Dead end check: 15% chance the research direction fails
    if (rng() < RESEARCH_DEAD_END_CHANCE) {
      // Reset progress — player must try again on the same node
      state.activeResearch.pointsAccumulated = 0;
      return { completed: null, deadEnd: true };
    }
    return { completed: completeTech(state, state.activeResearch.nodeId), deadEnd: false };
  }
  return { completed: null, deadEnd: false };
}

function completeTech(state: TechState, nodeId: string): string {
  const node = TECH_NODE_BY_ID.get(nodeId)!;
  state.unlockedMask |= 1n << BigInt(node.index);
  state.activeResearch = null;

  // Reveal hidden nodes whose prerequisites are now met
  for (const candidate of TECH_NODES) {
    if (!candidate.hidden) continue;
    if (isTechVisible(state, candidate.id)) continue;
    if (candidate.prerequisites.every((p) => isTechUnlocked(state, p))) {
      state.visibleMask |= 1n << BigInt(candidate.index);
    }
  }

  return nodeId;
}

/** Serialize TechState to a compact object (for messages/save) */
export function serializeTechState(state: TechState): SerializedTechState {
  return {
    unlockedMask: state.unlockedMask.toString(),
    visibleMask: state.visibleMask.toString(),
    activeResearch: state.activeResearch ? { ...state.activeResearch } : null,
    researchRate: state.researchRate,
    totalPointsGenerated: state.totalPointsGenerated,
  };
}

export interface SerializedTechState {
  unlockedMask: string;
  visibleMask: string;
  activeResearch: ActiveResearch | null;
  researchRate: number;
  totalPointsGenerated: number;
}

export function deserializeTechState(data: SerializedTechState): TechState {
  return {
    unlockedMask: BigInt(data.unlockedMask),
    visibleMask: BigInt(data.visibleMask),
    activeResearch: data.activeResearch ?? null,
    researchRate: data.researchRate,
    totalPointsGenerated: data.totalPointsGenerated,
  };
}
