import type { Discovery } from '../gameRuntimeState';
import {
  getRobotType,
  getRobotState,
} from '../sim/bufferLayout';
import { ANOMALY_TYPE_NAMES } from '../sim/anomalyTypes';
import { ROBOT_TYPE_NAMES as _ROBOT_TYPE_NAMES } from '../sim/robotProfiles';
import { ROBOT_STATE_NAMES as _ROBOT_STATE_NAMES } from '../sim/robotCreation';
import type { SerializedTechState } from '../sim/techTree';
import { TECH_NODE_BY_ID } from '../sim/techTree';
import type { MegastructureProjectSnapshot, MegastructureId } from '../shared/megastructureTypes';
import { MEGASTRUCTURE_DEFS, CRISIS_DEFS } from '../sim/megastructures';

export interface GameStateSummary {
  tick: number;
  resources: {
    iron: number;
    carbon: number;
    silicon: number;
    water: number;
  };
  refined: Record<string, number>;
  fleet: {
    total: number;
    robotCap: number;
    byType: Record<string, number>;
    byState: Record<string, number>;
  };
  research: {
    activeNodeId: string | null;
    progress: number; // 0-1
    researchRate: number;
  };
  factory: {
    queueLength: number;
  };
  discoveries: Array<{
    type: string;
    coords: [number, number, number];
    tick: number;
  }>;
  field: {
    totalAsteroids: number;
    activeMining: number;
  };
  buildings: Array<{ type: number; active: boolean }>;
  /** True once signal_analysis tech is unlocked — gates Aria's research direction advice */
  ariaCanDirectResearch: boolean;
  /** Megastructure projects with crisis-imminent status */
  megastructures: MegastructureCrisisInfo[];
  /** Faction standings for ARIA commentary */
  factionStandings: FactionStanding[];
}

/** Compact faction standing info for ARIA context */
export interface FactionStanding {
  name: string;
  disposition: number;
  label: string;
  trend: 'improving' | 'worsening' | 'stable';
}

/** Crisis-relevant info for a megastructure project */
export interface MegastructureCrisisInfo {
  id: MegastructureId;
  name: string;
  activeStageIndex: number | null;
  stageName: string | null;
  /** True if the active stage can trigger a crisis and hasn't yet */
  crisisEligible: boolean;
  /** Name of the crisis type that could fire, if any */
  crisisTypeName: string | null;
  /** Whether a crisis is currently active (blocking construction) */
  activeCrisis: boolean;
  stageProgressPct: number;
}

/**
 * Builds a compact game state summary for LLM context.
 * Stays well under 2000 tokens.
 */
export interface BuildGameStateOpts {
  storageValues: Float32Array;
  robotBuffer: Float32Array | null;
  robotCount: number;
  asteroidBuffer: Float64Array | null;
  asteroidCount: number;
  discoveries: Discovery[];
  currentTick: number;
  buildings?: Array<{ type: number; active: boolean }>;
  refined?: Record<string, number>;
  techState?: SerializedTechState | null;
  factoryQueueLength?: number;
  robotCap?: number;
}

export function buildGameState(
  storageValues: Float32Array,
  robotBuffer: Float32Array | null,
  robotCount: number,
  asteroidBuffer: Float64Array | null,
  asteroidCount: number,
  discoveries: Discovery[],
  currentTick: number,
  buildings: Array<{ type: number; active: boolean }> = [],
  opts?: {
    refined?: Record<string, number>;
    techState?: SerializedTechState | null;
    factoryQueueLength?: number;
    robotCap?: number;
    megastructureProjects?: MegastructureProjectSnapshot[];
    factionStandings?: FactionStanding[];
  },
): GameStateSummary {
  // Resources
  const resources = {
    iron: Math.floor(storageValues[0] || 0),
    carbon: Math.floor(storageValues[5] || 0),
    silicon: Math.floor(storageValues[6] || 0),
    water: Math.floor(storageValues[4] || 0),
  };

  // Fleet summary - robot buffer layout: [eid, x, y, z, rotation, typeEnum, stateEnum, energyPct] per robot
  const byType: Record<string, number> = {};
  const byState: Record<string, number> = {};
  let activeMining = 0;

  if (robotBuffer && robotCount > 0) {
    for (let i = 0; i < robotCount; i++) {
      const typeEnum = Math.round(getRobotType(robotBuffer, i));
      const stateEnum = Math.round(getRobotState(robotBuffer, i));
      const typeName = (_ROBOT_TYPE_NAMES[typeEnum] ?? 'unknown').toLowerCase();
      const stateName = (_ROBOT_STATE_NAMES[stateEnum] ?? 'unknown').toLowerCase();
      byType[typeName] = (byType[typeName] ?? 0) + 1;
      byState[stateName] = (byState[stateName] ?? 0) + 1;
      if (stateEnum === 2) activeMining++; // MINING state
    }
  }

  // Asteroid field stats — asteroid buffer used for count only here
  void asteroidBuffer;
  const miningActivity = activeMining;

  // Discoveries - cap at most recent 8 to stay under token budget
  const recentDiscoveries = discoveries.slice(-8).map((d) => ({
    type: ANOMALY_TYPE_NAMES[d.anomalyType] ?? 'Unknown',
    coords: [Math.round(d.x), Math.round(d.y), Math.round(d.z)] as [number, number, number],
    tick: d.tick,
  }));

  // Research progress
  const techState = opts?.techState;
  const activeResearch = techState?.activeResearch ?? null;
  const researchProgress = activeResearch
    ? Math.min(1, activeResearch.pointsAccumulated / Math.max(1, activeResearch.pointsRequired))
    : 0;

  // gate Aria's research direction advice behind signal_analysis unlock
  const signalAnalysisIndex = TECH_NODE_BY_ID.get('signal_analysis')?.index ?? -1;
  const ariaCanDirectResearch = techState != null && signalAnalysisIndex >= 0
    ? (BigInt(techState.unlockedMask) & (1n << BigInt(signalAnalysisIndex))) !== 0n
    : false;

  // Megastructure crisis info
  const megastructures: MegastructureCrisisInfo[] = (opts?.megastructureProjects ?? []).map((p) => {
    const def = MEGASTRUCTURE_DEFS[p.id as MegastructureId];
    const stageDef = p.activeStageIndex !== null ? def?.stages[p.activeStageIndex] : null;
    const crisisEligible = !!(
      stageDef?.crisisType &&
      !p.crisisFiredThisStage &&
      p.stageProgress > 0 &&
      !p.activeCrisis
    );
    const crisisDef = stageDef?.crisisType ? CRISIS_DEFS[stageDef.crisisType] : null;
    return {
      id: p.id as MegastructureId,
      name: def?.name ?? p.id,
      activeStageIndex: p.activeStageIndex,
      stageName: stageDef?.name ?? null,
      crisisEligible,
      crisisTypeName: crisisDef?.name ?? null,
      activeCrisis: p.activeCrisis !== null,
      stageProgressPct: p.stageProgressPct,
    };
  });

  return {
    tick: currentTick,
    resources,
    refined: opts?.refined ?? {},
    fleet: {
      total: robotCount,
      robotCap: opts?.robotCap ?? 0,
      byType,
      byState,
    },
    research: {
      activeNodeId: activeResearch?.nodeId ?? null,
      progress: researchProgress,
      researchRate: techState?.researchRate ?? 0,
    },
    factory: {
      queueLength: opts?.factoryQueueLength ?? 0,
    },
    discoveries: recentDiscoveries,
    field: {
      totalAsteroids: asteroidCount,
      activeMining: miningActivity,
    },
    buildings: buildings.filter((b) => b.active),
    ariaCanDirectResearch,
    megastructures,
    factionStandings: opts?.factionStandings ?? [],
  };
}

/**
 * Produces a short hash key from the significant game-state fields.
 * Quantizes values so minor fluctuations don't bust the cache:
 *   - Resources: bucketed to nearest 50
 *   - Tick: bucketed to nearest 10
 *   - Fleet/buildings: exact counts
 *   - Megastructures: rounded progress + crisis flags
 */
export function gameStateHash(state: GameStateSummary): string {
  const bucket = (v: number, step: number) => Math.floor(v / step) * step;

  const parts: Array<string | number> = [
    bucket(state.tick, 10),
    bucket(state.resources.iron, 50),
    bucket(state.resources.carbon, 50),
    bucket(state.resources.silicon, 50),
    bucket(state.resources.water, 50),
    state.fleet.total,
    state.field.activeMining,
    state.research.activeNodeId ?? '-',
    Math.round(state.research.progress * 10), // 10% granularity
    state.discoveries.length,
    state.buildings.length,
  ];

  // Megastructure crisis flags
  for (const m of state.megastructures) {
    parts.push(m.id, Math.round(m.stageProgressPct * 10), m.crisisEligible ? 1 : 0, m.activeCrisis ? 1 : 0);
  }

  // Faction standings (bucketed to nearest 10)
  for (const f of state.factionStandings) {
    parts.push(f.name, bucket(f.disposition, 10));
  }

  // djb2 hash of the joined parts
  const s = parts.join('|');
  let h = 5381;
  for (let i = 0; i < s.length; i++) {
    h = (((h << 5) + h) ^ s.charCodeAt(i)) >>> 0;
  }
  return h.toString(36);
}

/**
 * Serializes game state to a compact string for inclusion in LLM context.
 */
export function serializeGameState(state: GameStateSummary): string {
  const lines: string[] = [
    `OPERATION STATUS (tick ${state.tick})`,
    '',
    'RESOURCE STOCKPILES:',
    `  Iron: ${state.resources.iron} | Carbon: ${state.resources.carbon} | Silicon: ${state.resources.silicon} | Water: ${state.resources.water}`,
    '',
    `FLEET: ${state.fleet.total} robots`,
    `  By type: ${
      Object.entries(state.fleet.byType)
        .map(([k, v]) => `${v} ${k}`)
        .join(', ') || 'none'
    }`,
    `  By state: ${
      Object.entries(state.fleet.byState)
        .map(([k, v]) => `${v} ${k}`)
        .join(', ') || 'none'
    }`,
    '',
    `ASTEROID FIELD: ${state.field.totalAsteroids} asteroids visible, ${state.field.activeMining} actively mined`,
  ];

  // Refined materials
  const refinedEntries = Object.entries(state.refined).filter(([, v]) => v > 0);
  if (refinedEntries.length > 0) {
    lines.push(
      '',
      'REFINED MATERIALS:',
      `  ${refinedEntries.map(([k, v]) => `${k}: ${Math.floor(v)}`).join(' | ')}`,
    );
  }

  // Research
  if (state.research.activeNodeId) {
    const pct = Math.round(state.research.progress * 100);
    lines.push(
      '',
      `RESEARCH: "${state.research.activeNodeId}" in progress (${pct}%, rate: ${state.research.researchRate.toFixed(1)} RP/s)`,
    );
  } else {
    lines.push('', 'RESEARCH: idle — no active research');
  }

  // Factory
  if (state.factory.queueLength > 0) {
    lines.push(`FACTORY: ${state.factory.queueLength} robot(s) queued`);
  }

  // Robot cap
  if (state.fleet.robotCap > 0) {
    lines.push(`FLEET CAP: ${state.fleet.total}/${state.fleet.robotCap}`);
  }

  const BUILDING_NAMES: Record<number, string> = {
    0: 'Robot Factory', 1: 'Defense Turret', 2: 'Comm Relay',
    3: 'Solar Panel', 4: 'Thermal Radiator', 5: 'Solar Furnace',
    6: 'RTG Module', 7: 'Fission Reactor', 8: 'Fusion Reactor',
  };
  if (state.buildings.length > 0) {
    const byCounts: Record<string, number> = {};
    for (const b of state.buildings) {
      const name = BUILDING_NAMES[b.type] ?? 'Unknown';
      byCounts[name] = (byCounts[name] ?? 0) + 1;
    }
    lines.push('', `BASE STRUCTURES: ${Object.entries(byCounts).map(([k, v]) => `${v}x ${k}`).join(', ')}`);
  } else {
    lines.push('', 'BASE STRUCTURES: none constructed');
  }

  if (state.discoveries.length > 0) {
    lines.push('', 'ANOMALY DISCOVERIES:');
    for (const d of state.discoveries) {
      lines.push(`  [tick ${d.tick}] ${d.type} at (${d.coords.join(', ')})`);
    }
  } else {
    lines.push('', 'ANOMALY DISCOVERIES: none yet');
  }

  // Faction standings
  if (state.factionStandings.length > 0) {
    lines.push('', 'FACTION STANDINGS:');
    for (const f of state.factionStandings) {
      const trend = f.trend === 'improving' ? '↑' : f.trend === 'worsening' ? '↓' : '→';
      lines.push(`  ${f.name}: ${Math.round(f.disposition)} (${f.label}) ${trend}`);
    }
  }

  // Megastructure crisis context
  const activeProjects = state.megastructures.filter((m) => m.activeStageIndex !== null);
  if (activeProjects.length > 0) {
    lines.push('', 'MEGASTRUCTURES:');
    for (const m of activeProjects) {
      const pct = Math.round(m.stageProgressPct * 100);
      let status = `${m.name} — Stage "${m.stageName}" (${pct}% complete)`;
      if (m.activeCrisis) {
        status += ' [CRISIS ACTIVE — construction halted]';
      } else if (m.crisisEligible) {
        status += ` [WARNING: ${m.crisisTypeName} crisis possible — prepare resolution materials]`;
      }
      lines.push(`  ${status}`);
    }
  }

  return lines.join('\n');
}
